// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./interfaces/IInvoiceRegistry.sol";
import "./InvoiceNFT.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title InvoiceRegistry
 * @notice Registry for invoice creation and state management
 * @dev Manages invoice lifecycle: Issued → Financed → Paid → Cleared
 * @dev Automatically mints InvoiceNFT when invoice is created (RWA tokenization)
 */
contract InvoiceRegistry is IInvoiceRegistry, AccessControl {
    bytes32 public constant SETTLEMENT_ROUTER_ROLE = keccak256("SETTLEMENT_ROUTER_ROLE");
    bytes32 public constant ADVANCE_ENGINE_ROLE = keccak256("ADVANCE_ENGINE_ROLE");

    InvoiceNFT public immutable invoiceNFT;

    uint256 private _nextInvoiceId = 1;

    mapping(uint256 => Invoice) private _invoices;
    mapping(address => uint256[]) private _sellerInvoices;

    modifier validStatusTransition(uint256 invoiceId, InvoiceStatus newStatus) {
        Invoice storage invoice = _invoices[invoiceId];
        InvoiceStatus currentStatus = invoice.status;

        // Validate state transitions
        if (currentStatus == InvoiceStatus.Issued) {
            require(
                newStatus == InvoiceStatus.Financed || newStatus == InvoiceStatus.Paid,
                "Invalid transition from Issued"
            );
        } else if (currentStatus == InvoiceStatus.Financed) {
            require(newStatus == InvoiceStatus.Paid, "Invalid transition from Financed");
        } else if (currentStatus == InvoiceStatus.Paid) {
            require(newStatus == InvoiceStatus.Cleared, "Invalid transition from Paid");
        } else {
            revert("Invoice already cleared");
        }
        _;
    }

    constructor(address _invoiceNFT, address defaultAdmin) {
        invoiceNFT = InvoiceNFT(_invoiceNFT);
        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
    }

    /**
     * @notice Create a new invoice
     * @param buyer Buyer address
     * @param amount Invoice amount (6 decimals)
     * @param dueDate Unix timestamp for due date
     * @param metadataHash Optional hash of invoice metadata
     * @return invoiceId The created invoice ID
     */
    function createInvoice(
        address buyer,
        uint256 amount,
        uint256 dueDate,
        bytes32 metadataHash
    ) external returns (uint256) {
        require(buyer != address(0), "Invalid buyer");
        require(amount > 0, "Amount must be > 0");
        require(dueDate > block.timestamp, "Due date must be in future");

        uint256 invoiceId = _nextInvoiceId++;

        _invoices[invoiceId] = Invoice({
            invoiceId: invoiceId,
            seller: msg.sender,
            buyer: buyer,
            amount: amount,
            dueDate: dueDate,
            status: InvoiceStatus.Issued,
            metadataHash: metadataHash,
            createdAt: block.timestamp,
            paidAt: 0,
            clearedAt: 0
        });

        _sellerInvoices[msg.sender].push(invoiceId);

        // Mint InvoiceNFT (RWA tokenization)
        invoiceNFT.mintInvoiceNFT(invoiceId, msg.sender);

        emit InvoiceCreated(invoiceId, msg.sender, buyer, amount, dueDate, metadataHash);

        return invoiceId;
    }

    /**
     * @notice Get invoice details
     */
    function getInvoice(uint256 invoiceId) external view returns (Invoice memory) {
        require(_invoices[invoiceId].invoiceId != 0, "Invoice not found");
        return _invoices[invoiceId];
    }

    /**
     * @notice Get all invoices for a seller
     */
    function getSellerInvoices(address seller) external view returns (uint256[] memory) {
        return _sellerInvoices[seller];
    }

    /**
     * @notice Update invoice status (restricted to authorized contracts)
     */
    function updateInvoiceStatus(
        uint256 invoiceId,
        InvoiceStatus newStatus
    ) external validStatusTransition(invoiceId, newStatus) {
        Invoice storage invoice = _invoices[invoiceId];
        require(invoice.invoiceId != 0, "Invoice not found");

        // Check permissions based on transition
        if (newStatus == InvoiceStatus.Financed) {
            require(hasRole(ADVANCE_ENGINE_ROLE, msg.sender), "Not authorized to finance");
        } else if (newStatus == InvoiceStatus.Paid || newStatus == InvoiceStatus.Cleared) {
            require(hasRole(SETTLEMENT_ROUTER_ROLE, msg.sender), "Not authorized to SETTL.e");
        }

        invoice.status = newStatus;

        if (newStatus == InvoiceStatus.Paid) {
            invoice.paidAt = block.timestamp;
            emit InvoicePaid(invoiceId, invoice.buyer, invoice.amount);
        } else if (newStatus == InvoiceStatus.Cleared) {
            invoice.clearedAt = block.timestamp;
        }
    }

    /**
     * @notice Mark invoice as financed (called by AdvanceEngine)
     */
    function markFinanced(uint256 invoiceId, uint256 advanceAmount) external {
        require(hasRole(ADVANCE_ENGINE_ROLE, msg.sender), "Not authorized");
        require(_invoices[invoiceId].status == InvoiceStatus.Issued, "Invalid status");

        _invoices[invoiceId].status = InvoiceStatus.Financed;
        emit InvoiceFinanced(invoiceId, _invoices[invoiceId].seller, advanceAmount);
    }

    /**
     * @notice Mark invoice as cleared with SETTL.ement details (called by SETTL.ementRouter)
     */
    function markCleared(
        uint256 invoiceId,
        uint256 sellerAmount,
        uint256 feeAmount,
        uint256 repaymentAmount
    ) external {
        require(hasRole(SETTLEMENT_ROUTER_ROLE, msg.sender), "Not authorized");
        require(_invoices[invoiceId].status == InvoiceStatus.Paid, "Must be Paid");

        _invoices[invoiceId].status = InvoiceStatus.Cleared;
        _invoices[invoiceId].clearedAt = block.timestamp;

        emit InvoiceCleared(invoiceId, _invoices[invoiceId].seller, sellerAmount, feeAmount, repaymentAmount);
    }
}

contracts/Reputation.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./interfaces/IReputation.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title Reputation
 * @notice On-chain reputation system for sellers
 * @dev Updates score and tier based on cleared invoices
 */
contract Reputation is IReputation, AccessControl {
    bytes32 public constant SETTLEMENT_ROUTER_ROLE = keccak256("SETTLEMENT_ROUTER_ROLE");

    mapping(address => SellerStats) private _stats;

    // Tier thresholds (score ranges)
    uint256 private constant TIER_C_MAX = 450;   // 0-450 (Tier C: 0-450)
    uint256 private constant TIER_B_MIN = 500;   // Tier B starts at 500
    uint256 private constant TIER_B_MAX = 850;   // Tier B: 500-850
    // Tier A: 850-1000

    // Score calculation constants
    uint256 private constant BASE_SCORE_INCREMENT = 20;  // Base points per cleared invoice (20 points per repayment)
    uint256 private constant VOLUME_BONUS_DIVISOR = 1000000000000; // 1M USDC = 1 bonus point (1M * 1e6 decimals = 1e12)

    constructor(address defaultAdmin) {
        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
    }

    /**
     * @notice Update reputation after invoice cleared (called by SETTL.ementRouter)
     * @param seller Seller address
     * @param invoiceAmount Invoice amount in USDC
     */
    function updateReputation(address seller, uint256 invoiceAmount) external onlyRole(SETTLEMENT_ROUTER_ROLE) {
        SellerStats storage stats = _stats[seller];

        // Initialize new users with starting score of 450 (Tier C minimum)
        // Check BEFORE incrementing cleared count
        bool isNewUser = (stats.score == 0 && stats.invoicesCleared == 0);
        if (isNewUser) {
            stats.score = 450; // Start at Tier C minimum (450)
            stats.tier = Tier.C;
        }

        // Increment cleared count
        stats.invoicesCleared += 1;
        stats.totalVolume += invoiceAmount;

        // Calculate score increment
        // Base: +20 per cleared invoice (repayment reward)
        // Bonus: +1 per $1M volume (scaled for 6 decimals)
        uint256 baseIncrement = BASE_SCORE_INCREMENT; // 20 points per repayment
        uint256 volumeBonus = invoiceAmount / VOLUME_BONUS_DIVISOR;
        uint256 scoreIncrement = baseIncrement + volumeBonus;

        // Update score (capped at 1000)
        uint256 newScore = stats.score + scoreIncrement;
        if (newScore > 1000) {
            newScore = 1000;
        }
        stats.score = newScore;

        // Determine tier
        // Tier C: 0-450, Tier B: 500-850, Tier A: 850-1000
        // Note: Scores 451-499 remain Tier C until reaching 500
        if (newScore < TIER_B_MIN) {
            stats.tier = Tier.C;  // 0-499 are Tier C
        } else if (newScore < 850) {
            stats.tier = Tier.B;   // 500-849 are Tier B
        } else {
            stats.tier = Tier.A;   // 850-1000 are Tier A
        }

        stats.lastUpdated = block.timestamp;

        emit ReputationUpdated(seller, newScore, stats.tier, invoiceAmount);
    }

    /**
     * @notice Get seller's reputation score (0-1000)
     * @dev New users start with 450 (Tier C minimum)
     */
    function getScore(address seller) external view returns (uint256) {
        uint256 score = _stats[seller].score;
        // If user has no score yet, return default starting score of 450 (Tier C)
        if (score == 0 && _stats[seller].invoicesCleared == 0) {
            return 450;
        }
        return score;
    }

    /**
     * @notice Get seller's tier (A/B/C)
     * @dev New users start at Tier C
     */
    function getTier(address seller) external view returns (Tier) {
        SellerStats memory stats = _stats[seller];
        // If user has no score yet, return Tier C
        if (stats.score == 0 && stats.invoicesCleared == 0) {
            return Tier.C;
        }
        return stats.tier;
    }

    /**
     * @notice Get full seller stats
     * @dev New users start with score 450 (Tier C minimum)
     */
    function getStats(address seller) external view returns (SellerStats memory) {
        SellerStats memory stats = _stats[seller];
        // If user has no stats yet, return default starting stats (450, Tier C)
        if (stats.score == 0 && stats.invoicesCleared == 0) {
            return SellerStats({
                score: 450,
                tier: Tier.C,
                invoicesCleared: 0,
                totalVolume: 0,
                lastUpdated: 0
            });
        }
        return stats;
    }
}

contracts/SettlementRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./interfaces/IInvoiceRegistry.sol";
import "./interfaces/IVault.sol";
import "./interfaces/IAdvanceEngine.sol";
import "./interfaces/IReputation.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title SETTL.ementRouter
 * @notice Executes atomic SETTL.ement waterfall: fee → pool repayment → seller remainder
 * @dev This is the core contract that orchestrates payment SETTL.ement
 */
contract SettlementRouter is AccessControl {
    using SafeERC20 for IERC20;

    IERC20 public immutable token; // DemoUSDC
    IInvoiceRegistry public immutable invoiceRegistry;
    IVault public immutable vault;
    IAdvanceEngine public immutable advanceEngine;
    IReputation public immutable reputation;

    address public treasury; // Fee recipient
    uint256 public protocolFeeBps; // Protocol fee in basis points (e.g., 50 = 0.5%)

    uint256 private constant BASIS_POINTS = 10000;

    event InvoiceSettled(
        uint256 indexed invoiceId,
        address indexed buyer,
        address indexed seller,
        uint256 invoiceAmount,
        uint256 feeAmount,
        uint256 repaymentAmount,
        uint256 sellerAmount
    );

    constructor(
        address _token,
        address _invoiceRegistry,
        address _vault,
        address _advanceEngine,
        address _reputation,
        address _treasury,
        uint256 _protocolFeeBps,
        address defaultAdmin
    ) {
        token = IERC20(_token);
        invoiceRegistry = IInvoiceRegistry(_invoiceRegistry);
        vault = IVault(_vault);
        advanceEngine = IAdvanceEngine(_advanceEngine);
        reputation = IReputation(_reputation);
        treasury = _treasury;
        protocolFeeBps = _protocolFeeBps;

        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
    }

    /**
     * @notice Pay an invoice and execute SETTL.ement waterfall atomically
     * @param invoiceId Invoice ID to pay
     */
    function payInvoice(uint256 invoiceId) external {
        IInvoiceRegistry.Invoice memory invoice = invoiceRegistry.getInvoice(invoiceId);
        require(invoice.invoiceId != 0, "Invoice not found");
        require(invoice.status != IInvoiceRegistry.InvoiceStatus.Cleared, "Already cleared");
        require(invoice.buyer == msg.sender, "Not invoice buyer");

        // Pull payment from buyer
        token.safeTransferFrom(msg.sender, address(this), invoice.amount);

        // Update invoice status to Paid
        invoiceRegistry.updateInvoiceStatus(invoiceId, IInvoiceRegistry.InvoiceStatus.Paid);

        // Calculate SETTL.ement amounts
        uint256 feeAmount = (invoice.amount * protocolFeeBps) / BASIS_POINTS;

        // Check if invoice was financed
        uint256 repaymentAmount = 0;
        try advanceEngine.getRepaymentAmount(invoiceId) returns (uint256 amount) {
            repaymentAmount = amount;
        } catch {
            // Invoice not financed, no repayment
        }

        // Calculate seller remainder: invoiceAmount - fee - repayment
        uint256 sellerAmount = invoice.amount - feeAmount - repaymentAmount;

        // Verify math: fee + repayment + seller = invoiceAmount
        require(
            feeAmount + repaymentAmount + sellerAmount == invoice.amount,
            "SETTL.ement math mismatch"
        );

        // Execute waterfall atomically:
        // 1. Send fee to treasury
        if (feeAmount > 0) {
            token.safeTransfer(treasury, feeAmount);
        }

        // 2. Repay vault (if financed)
        if (repaymentAmount > 0) {
            // Approve vault to pull repayment from this contract
            // Note: Using approve directly since we control the flow and reset to zero after
            token.approve(address(vault), repaymentAmount);
            // Vault will transfer repayment from this contract via safeTransferFrom
            vault.repay(repaymentAmount);
            // Reset approval to zero (gas optimization and security)
            token.approve(address(vault), 0);
            // Mark advance as repaid
            advanceEngine.markRepaid(invoiceId);
        }

        // 3. Send remainder to seller
        if (sellerAmount > 0) {
            token.safeTransfer(invoice.seller, sellerAmount);
        }

        // 4. Mark invoice as cleared
        invoiceRegistry.markCleared(invoiceId, sellerAmount, feeAmount, repaymentAmount);

        // 5. Update reputation (must succeed - atomic operation)
        // If reputation update fails, entire transaction reverts (invoice remains uncleared)
        // This ensures reputation is always updated when invoices are cleared
        reputation.updateReputation(invoice.seller, invoice.amount);

        emit InvoiceSettled(
            invoiceId,
            msg.sender,
            invoice.seller,
            invoice.amount,
            feeAmount,
            repaymentAmount,
            sellerAmount
        );
    }

    /**
     * @notice Set protocol fee (admin only)
     */
    function setProtocolFee(uint256 newFeeBps) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newFeeBps <= 500, "Fee too high"); // Max 5%
        protocolFeeBps = newFeeBps;
    }

    /**
     * @notice Set treasury address (admin only)
     */
    function setTreasury(address newTreasury) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newTreasury != address(0), "Invalid treasury");
        treasury = newTreasury;
    }
}

contracts/Staking.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title Staking
 * @notice Staking contract for USMT+ tokens. Users stake USMT+ and receive sUSMT+ (staked USMT+)
 * @dev sUSMT+ accrues yield over time based on staking rewards
 */
contract Staking is ERC20, AccessControl {
    using SafeERC20 for IERC20;

    bytes32 public constant REWARDS_DISTRIBUTOR_ROLE = keccak256("REWARDS_DISTRIBUTOR_ROLE");

    IERC20 public immutable usmtPlus; // USMT+ token
    uint256 public totalStaked; // Total USMT+ staked
    uint256 public totalRewardsDistributed; // Total rewards distributed (for tracking)

    // Staking info per user
    mapping(address => uint256) public stakedBalance; // User's staked USMT+ amount

    uint256 private constant DECIMALS = 1e6; // 6 decimals

    event Stake(address indexed user, uint256 usmtAmount, uint256 susmtAmount);
    event Unstake(address indexed user, uint256 usmtAmount, uint256 susmtAmount);
    event RewardsDistributed(uint256 totalAmount);

    constructor(address _usmtPlus, address defaultAdmin) ERC20("Staked USMT+", "sUSMT+") {
        usmtPlus = IERC20(_usmtPlus);
        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
    }

    function decimals() public pure override returns (uint8) {
        return 6; // Match USMT+ decimals
    }

    /**
     * @notice Stake USMT+ and receive sUSMT+
     * @param amount Amount of USMT+ to stake (6 decimals)
     * @return susmtAmount Amount of sUSMT+ minted
     */
    function stake(uint256 amount) external returns (uint256 susmtAmount) {
        require(amount > 0, "Amount must be > 0");

        // Transfer USMT+ from user
        usmtPlus.safeTransferFrom(msg.sender, address(this), amount);

        // Calculate sUSMT+ to mint (1:1 for now, but can be adjusted for yield accumulation)
        // In future, this could use an exchange rate based on accumulated yield
        susmtAmount = amount;

        // Mint sUSMT+ to user
        _mint(msg.sender, susmtAmount);

        // Update staking info
        stakedBalance[msg.sender] += amount;
        totalStaked += amount;

        emit Stake(msg.sender, amount, susmtAmount);
        return susmtAmount;
    }

    /**
     * @notice Unstake USMT+ by burning sUSMT+
     * @param susmtAmount Amount of sUSMT+ to burn (6 decimals)
     * @return usmtAmount Amount of USMT+ returned
     */
    function unstake(uint256 susmtAmount) external returns (uint256 usmtAmount) {
        require(susmtAmount > 0, "Amount must be > 0");
        require(balanceOf(msg.sender) >= susmtAmount, "Insufficient sUSMT+ balance");

        // Calculate USMT+ to return (1:1 for now)
        // In future, this could use an exchange rate based on accumulated yield
        usmtAmount = susmtAmount;
        require(stakedBalance[msg.sender] >= usmtAmount, "Insufficient staked balance");

        // Burn sUSMT+ from user
        _burn(msg.sender, susmtAmount);

        // Transfer USMT+ back to user
        usmtPlus.safeTransfer(msg.sender, usmtAmount);

        // Update staking info
        stakedBalance[msg.sender] -= usmtAmount;
        totalStaked -= usmtAmount;

        emit Unstake(msg.sender, usmtAmount, susmtAmount);
        return usmtAmount;
    }

    /**
     * @notice Get user's staked balance
     * @param user User address
     * @return Amount of USMT+ staked by user
     */
    function getStakedBalance(address user) external view returns (uint256) {
        return stakedBalance[user];
    }

    /**
     * @notice Get user's sUSMT+ balance (staked token balance)
     * @param user User address
     * @return Amount of sUSMT+ held by user
     */
    function getSusmtBalance(address user) external view returns (uint256) {
        return balanceOf(user);
    }

    /**
     * @notice Distribute rewards (to be called by rewards distributor)
     * @dev In future, this could mint additional sUSMT+ to stakers or transfer USMT+ rewards
     * For now, this is a placeholder for future yield distribution logic
     */
    function distributeRewards(uint256 amount) external onlyRole(REWARDS_DISTRIBUTOR_ROLE) {
        require(amount > 0, "Amount must be > 0");
        // TODO: Implement reward distribution logic
        // For now, just track total rewards distributed
        totalRewardsDistributed += amount;
        emit RewardsDistributed(amount);
    }
}

contracts/USMTPlus.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title USMTPlus (USMT+)
 * @notice Receipt token for vault deposits. Users deposit USDC and receive USMT+ 1:1
 * @dev Mintable only by Vault contract
 */
contract USMTPlus is ERC20, AccessControl {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");

    uint8 private constant DECIMALS = 6; // Match USDC decimals

    constructor(address defaultAdmin) ERC20("USMT+", "USMT+") {
        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
        _grantRole(MINTER_ROLE, defaultAdmin); // Admin can grant MINTER_ROLE to Vault
    }

    function decimals() public pure override returns (uint8) {
        return DECIMALS;
    }

    /**
     * @notice Mint USMT+ tokens (only by Vault)
     * @param to Address to mint tokens to
     * @param amount Amount to mint (6 decimals)
     */
    function mint(address to, uint256 amount) external onlyRole(MINTER_ROLE) {
        _mint(to, amount);
    }

    /**
     * @notice Burn USMT+ tokens (only by Vault)
     * @param from Address to burn tokens from
     * @param amount Amount to burn (6 decimals)
     */
    function burn(address from, uint256 amount) external onlyRole(MINTER_ROLE) {
        _burn(from, amount);
    }
}

contracts/Vault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./interfaces/IVault.sol";
import "./USMTPlus.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title Vault
 * @notice Simple funding pool for LP deposits and borrowings
 * @dev Users deposit USDC and receive USMT+ tokens 1:1
 */
contract Vault is IVault, AccessControl {
    using SafeERC20 for IERC20;

    bytes32 public constant BORROWER_ROLE = keccak256("BORROWER_ROLE");

    IERC20 public immutable token; // DemoUSDC (USDC)
    USMTPlus public immutable usmtPlus; // USMT+ receipt token

    uint256 public totalLiquidity;    // Total USDC deposited
    uint256 public totalBorrowed;     // Total USDC borrowed

    uint256 private constant PRECISION = 1e18;

    constructor(address _token, address _usmtPlus, address defaultAdmin) {
        token = IERC20(_token);
        usmtPlus = USMTPlus(_usmtPlus);
        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
    }

    /**
     * @notice Deposit USDC and receive USMT+ tokens 1:1
     * @param amount Amount to deposit (6 decimals)
     * @return usmtReceived Number of USMT+ tokens minted (1:1 with deposit)
     */
    function deposit(uint256 amount) external returns (uint256 usmtReceived) {
        require(amount > 0, "Amount must be > 0");

        // Transfer USDC from user
        token.safeTransferFrom(msg.sender, address(this), amount);

        // Mint USMT+ tokens 1:1
        usmtReceived = amount;
        usmtPlus.mint(msg.sender, usmtReceived);

        totalLiquidity += amount;

        emit Deposit(msg.sender, amount, usmtReceived);
        return usmtReceived;
    }

    /**
     * @notice Withdraw USDC by burning USMT+ tokens 1:1
     * @param usmtAmount Number of USMT+ tokens to burn
     * @return amountReceived USDC amount received (1:1 with USMT+ burned)
     */
    function withdraw(uint256 usmtAmount) external returns (uint256 amountReceived) {
        require(usmtAmount > 0, "Amount must be > 0");

        // Check available liquidity
        uint256 availableLiquidity = totalLiquidity - totalBorrowed;
        require(availableLiquidity >= usmtAmount, "Insufficient liquidity");

        // Burn USMT+ tokens from user
        usmtPlus.burn(msg.sender, usmtAmount);

        // Return USDC 1:1
        amountReceived = usmtAmount;
        totalLiquidity -= amountReceived;

        token.safeTransfer(msg.sender, amountReceived);

        emit Withdraw(msg.sender, usmtAmount, amountReceived);
        return amountReceived;
    }

    /**
     * @notice Borrow USDC from vault (called by AdvanceEngine)
     */
    function borrow(uint256 amount) external onlyRole(BORROWER_ROLE) {
        require(amount > 0, "Amount must be > 0");
        uint256 availableLiquidity = totalLiquidity - totalBorrowed;
        require(availableLiquidity >= amount, "Insufficient liquidity");

        totalBorrowed += amount;
        token.safeTransfer(msg.sender, amount);

        emit Borrow(msg.sender, amount);
    }

    /**
     * @notice Repay borrowed USDC (called by SETTL.ementRouter)
     */
    function repay(uint256 amount) external {
        require(amount > 0, "Amount must be > 0");
        require(totalBorrowed >= amount, "Repay exceeds borrowed");

        token.safeTransferFrom(msg.sender, address(this), amount);
        totalBorrowed -= amount;
        // Note: totalLiquidity stays the same (repayment increases available liquidity)

        emit Repay(msg.sender, amount);
    }

    /**
     * @notice Get total liquidity (deposited USDC)
     */
    function getTotalLiquidity() external view returns (uint256) {
        return totalLiquidity;
    }

    /**
     * @notice Get total borrowed amount
     */
    function getTotalBorrowed() external view returns (uint256) {
        return totalBorrowed;
    }

    /**
     * @notice Get utilization rate (0-10000, where 10000 = 100%)
     */
    function getUtilizationRate() external view returns (uint256) {
        if (totalLiquidity == 0) return 0;
        return (totalBorrowed * 10000) / totalLiquidity;
    }

    /**
     * @notice Get user's USMT+ balance (receipt tokens)
     */
    function getShares(address user) external view returns (uint256) {
        return usmtPlus.balanceOf(user);
    }

    /**
     * @notice Get user's USDC balance (same as USMT+ balance since 1:1)
     */
    function getBalance(address user) external view returns (uint256) {
        return usmtPlus.balanceOf(user);
    }

    /**
     * @notice Get total USMT+ supply (total shares)
     */
    function totalShares() external view returns (uint256) {
        return usmtPlus.totalSupply();
    }
}

